css:
* { margin: 0; padding: 0; box-sizing: border-box; font-family: -apple-system, BlinkMacSystemFont, 'Segoe UI', sans-serif; }
body { background: #0a0e1a; color: white; }
.navbar { display: flex; align-items: center; justify-content: space-between; padding: 24px 60px; }
.brand { font-size: 19px; font-weight: 800; }
.nav-links { display: flex; gap: 28px; }
.nav-links a { color: rgba(255,255,255,0.5); text-decoration: none; font-size: 14px; font-weight: 600; }
.hero { text-align: center; padding: 50px 60px; }
.hero h1 { font-size: 44px; font-weight: 800; line-height: 1.3; margin-bottom: 14px; }
.hero h1 span { color: #6366f1; }
.hero p { color: rgba(255,255,255,0.5); font-size: 15px; margin-bottom: 30px; }
.toggle-row { display: flex; align-items: center; justify-content: center; gap: 14px; font-size: 14px; font-weight: 700; }
.toggle { width: 50px; height: 28px; background: rgba(255,255,255,0.1); border-radius: 999px; position: relative; cursor: pointer; }
.toggle.on { background: #6366f1; }
.toggle-dot { position: absolute; top: 3px; left: 3px; width: 22px; height: 22px; background: white; border-radius: 50%; transition: 0.2s; }
.toggle.on .toggle-dot { left: 25px; }
.save-badge { background: rgba(74,222,128,0.15); color: #4ade80; font-size: 11px; font-weight: 800; padding: 3px 8px; border-radius: 999px; margin-left: 6px; }
.plans { display: grid; grid-template-columns: repeat(auto-fit, minmax(260px, 1fr)); gap: 24px; padding: 0 60px 70px; max-width: 1100px; margin: 0 auto; }
.plan-card { background: rgba(255,255,255,0.03); border: 1px solid rgba(255,255,255,0.08); border-radius: 20px; padding: 32px; position: relative; }
.plan-card.highlighted { border-color: #6366f1; background: rgba(99,102,241,0.06); transform: scale(1.02); }
.popular-badge { position: absolute; top: -12px; left: 50%; transform: translateX(-50%); background: #6366f1; color: white; font-size: 11px; font-weight: 800; padding: 5px 16px; border-radius: 999px; }
.plan-card h3 { font-size: 20px; font-weight: 800; margin-bottom: 14px; }
.plan-price { display: flex; align-items: baseline; gap: 6px; margin-bottom: 14px; }
.amount { font-size: 40px; font-weight: 800; }
.period { font-size: 14px; color: rgba(255,255,255,0.4); font-weight: 600; }
.plan-desc { color: rgba(255,255,255,0.45); font-size: 13.5px; margin-bottom: 24px; }
.features { list-style: none; display: flex; flex-direction: column; gap: 12px; margin-bottom: 28px; }
.features li { font-size: 13.5px; color: rgba(255,255,255,0.75); }
.features li.disabled { color: rgba(255,255,255,0.3); }
.plan-card button { width: 100%; background: rgba(255,255,255,0.06); border: 1px solid rgba(255,255,255,0.1); color: white; padding: 14px; border-radius: 12px; font-size: 14px; font-weight: 700; cursor: pointer; }
.plan-card button.primary { background: #6366f1; border-color: #6366f1; }
.faq { padding: 0 60px 80px; max-width: 700px; margin: 0 auto; }
.faq h2 { font-size: 28px; font-weight: 800; text-align: center; margin-bottom: 30px; }
.faq-item { border-bottom: 1px solid rgba(255,255,255,0.08); padding: 18px 0; cursor: pointer; }
.faq-q { display: flex; justify-content: space-between; font-size: 15px; font-weight: 700; }
.faq-a { color: rgba(255,255,255,0.5); font-size: 13.5px; line-height: 1.7; margin-top: 12px; display: none; }
.faq-item.open .faq-a { display: block; }
.faq-item.open .faq-q span { transform: rotate(45deg); }
.faq-q span { transition: 0.2s; }
@media (max-width: 900px) { .navbar, .hero, .plans, .faq { padding-left: 24px; padding-right: 24px; } .nav-links { display: none; } .hero h1 { font-size: 30px; } .plan-card.highlighted { transform: none; } }

js:
let yearly = false;

function toggleBilling() {
  yearly = !yearly;
  document.getElementById('billingToggle').classList.toggle('on', yearly);
  document.querySelectorAll('.amount').forEach(el => {
    const price = yearly ? el.dataset.yearly : el.dataset.monthly;
    el.textContent = `₺${price}`;
  });
}

function selectPlan(name) {
  alert(`"${name}" planı seçildi. ${yearly ? 'Yıllık' : 'Aylık'} faturalandırma.`);
}

function toggleFaq(el) {
  el.classList.toggle('open');
}
